CREATE TABLE `pat_patients` (
  `ID` int NOT NULL AUTO_INCREMENT,
  `CODE` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Patient code (internal identifier)',
  `MRN` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Medical Record Number',
  `EXTERNAL_ID` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'External system identifier',
  `HOSPITAL_ID` int NOT NULL COMMENT 'Primary hospital',
  `BRANCH_ID` int DEFAULT NULL COMMENT 'Primary branch',
  `REGISTERED_AT` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT 'Registration timestamp',
  `REGISTRATION_TYPE` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'OUTPATIENT' COMMENT 'Type: OUTPATIENT, INPATIENT, EMERGENCY',
  `PATIENT_STATUS` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'ACTIVE' COMMENT 'Status: ACTIVE, INACTIVE, DECEASED, TRANSFERRED',
  `PATIENT_TYPE` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Type: ADULT, PEDIATRIC, GERIATRIC, MATERNITY',
  `ETHNICITY` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Ethnicity',
  `NATIONALITY` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'Vietnam' COMMENT 'Nationality',
  `PREFERRED_LANGUAGE` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'vi' COMMENT 'Preferred language',
  `RELIGION` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Religion',
  `OCCUPATION` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Occupation',
  `EMPLOYER` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Employer',
  `EDUCATION_LEVEL` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Education level',
  `MARITAL_STATUS` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Marital status',
  `BLOOD_TYPE` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Blood type',
  `ORGAN_DONOR` tinyint(1) DEFAULT '0' COMMENT 'Organ donor status',
  `ADVANCE_DIRECTIVE` tinyint(1) DEFAULT '0' COMMENT 'Has advance directive',
  `DNR_STATUS` tinyint(1) DEFAULT '0' COMMENT 'Do Not Resuscitate status',
  `PRIMARY_CARE_PROVIDER_ID` int DEFAULT NULL COMMENT 'Primary care provider',
  `REFERRING_PROVIDER_ID` int DEFAULT NULL COMMENT 'Referring provider',
  `LAST_VISIT_DATE` datetime DEFAULT NULL COMMENT 'Last visit date',
  `NEXT_APPOINTMENT_DATE` datetime DEFAULT NULL COMMENT 'Next appointment date',
  `VIP_STATUS` tinyint(1) DEFAULT '0' COMMENT 'VIP patient status',
  `HIGH_RISK_PATIENT` tinyint(1) DEFAULT '0' COMMENT 'High risk patient flag',
  `CONFIDENTIAL_PATIENT` tinyint(1) DEFAULT '0' COMMENT 'Confidential patient (celebrity, politician, etc.)',
  `DECEASED_DATE` datetime DEFAULT NULL COMMENT 'Date of death',
  `DECEASED_CAUSE` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Cause of death',
  `PROFILE_PICTURE_URL` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Profile picture URL',
  `CONSENT_FOR_PHOTOS` tinyint(1) DEFAULT '0' COMMENT 'Consent for using photos',
  `MARKETING_OPT_OUT` tinyint(1) DEFAULT '0' COMMENT 'Opt out of marketing communications',
  `RESEARCH_OPT_IN` tinyint(1) DEFAULT '0' COMMENT 'Opt in for research studies',
  `DATA_RETENTION_PREFERENCE` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'STANDARD' COMMENT 'Data retention preference',
  `LAST_ASSESSMENT_DATE` datetime DEFAULT NULL COMMENT 'Last comprehensive assessment',
  `RISK_SCORE` decimal(5,2) DEFAULT NULL COMMENT 'Patient risk score',
  `COMPLIANCE_SCORE` decimal(5,2) DEFAULT NULL COMMENT 'Treatment compliance score',
  `SATISFACTION_SCORE` decimal(3,1) DEFAULT NULL COMMENT 'Patient satisfaction score',
  `NOTES` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT 'General notes',
  `CREATED_AT` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `LAST_UPDATED_AT` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `STATUS` int NOT NULL DEFAULT '1',
  `CREATED_BY` int DEFAULT NULL,
  `LAST_UPDATED_BY` int DEFAULT NULL,
  `LAST_UPDATED_PROGRAM` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  PRIMARY KEY (`ID`),
  UNIQUE KEY `UK_CODE` (`CODE`),
  UNIQUE KEY `UK_MRN_HOSPITAL` (`MRN`,`HOSPITAL_ID`),
  KEY `IDX_HOSPITAL_ID` (`HOSPITAL_ID`),
  KEY `IDX_BRANCH_ID` (`BRANCH_ID`),
  KEY `IDX_PATIENT_STATUS` (`PATIENT_STATUS`),
  KEY `IDX_PATIENT_TYPE` (`PATIENT_TYPE`),
  KEY `IDX_REGISTRATION_TYPE` (`REGISTRATION_TYPE`),
  KEY `IDX_BLOOD_TYPE` (`BLOOD_TYPE`),
  KEY `IDX_LAST_VISIT_DATE` (`LAST_VISIT_DATE`),
  KEY `IDX_NEXT_APPOINTMENT_DATE` (`NEXT_APPOINTMENT_DATE`),
  KEY `IDX_PRIMARY_CARE_PROVIDER_ID` (`PRIMARY_CARE_PROVIDER_ID`),
  KEY `IDX_VIP_STATUS` (`VIP_STATUS`),
  KEY `IDX_HIGH_RISK_PATIENT` (`HIGH_RISK_PATIENT`),
  KEY `IDX_STATUS` (`STATUS`),
  KEY `IDX_CREATED_AT` (`CREATED_AT`),
  KEY `FK_PATIENT_REF_PROVIDER` (`REFERRING_PROVIDER_ID`),
  KEY `IDX_PAT_PATIENTS_HOSPITAL_ID` (`HOSPITAL_ID`),
  KEY `IDX_PAT_PATIENTS_BRANCH_ID` (`BRANCH_ID`),
  KEY `IDX_PAT_PATIENTS_PATIENT_STATUS` (`PATIENT_STATUS`),
  KEY `IDX_PAT_PATIENTS_LAST_VISIT_DATE` (`LAST_VISIT_DATE`),
  KEY `IDX_PAT_PATIENTS_NEXT_APPOINTMENT_DATE` (`NEXT_APPOINTMENT_DATE`),
  CONSTRAINT `FK_PATIENT_BRANCH` FOREIGN KEY (`BRANCH_ID`) REFERENCES `sys_branches` (`ID`),
  CONSTRAINT `FK_PATIENT_HOSPITAL` FOREIGN KEY (`HOSPITAL_ID`) REFERENCES `sys_hospitals` (`ID`),
  CONSTRAINT `FK_PATIENT_PC_PROVIDER` FOREIGN KEY (`PRIMARY_CARE_PROVIDER_ID`) REFERENCES `sta_doctors` (`ID`),
  CONSTRAINT `FK_PATIENT_REF_PROVIDER` FOREIGN KEY (`REFERRING_PROVIDER_ID`) REFERENCES `sta_doctors` (`ID`)
) ENGINE=InnoDB AUTO_INCREMENT=203 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='Patient Master Information';
